int minAddToMakeValidNaive(string s) {
    int moves = 0;
    while (!s.empty()) {
        bool removed = false;
        for (size_t i = 0; i < s.size() - 1; i++) {
            if (s[i] == '(' && s[i + 1] == ')') {
                // Remove the valid pair
                s.erase(i, 2);
                removed = true;
                break;
            }
        }
        if (!removed) {
            // If no pairs found, remaining length = number of insertions needed
            moves += s.size();
            break;
        }
    }
    return moves;
}

