int minAddToMakeValidNaive(char *s) {
    int moves = 0;
    int len = strlen(s);
    char temp[2000]; // large enough buffer
    strcpy(temp, s);

    while (len > 0) {
        int removed = 0;
        for (int i = 0; i < len - 1; i++) {
            if (temp[i] == '(' && temp[i + 1] == ')') {
                // remove the valid pair
                for (int j = i; j < len - 2; j++) {
                    temp[j] = temp[j + 2];
                }
                len -= 2;
                removed = 1;
                break;
            }
        }
        if (!removed) {
            // If no pairs found, remaining length is the number of insertions needed
            moves += len;
            break;
        }
    }

    return moves;
}

