function minAddToMakeValidNaive(s) {
    let moves = 0;
    s = s.split(''); // convert to array for easier manipulation

    while (s.length > 0) {
        let removed = false;
        for (let i = 0; i < s.length - 1; i++) {
            if (s[i] === '(' && s[i + 1] === ')') {
                // remove the pair
                s.splice(i, 2);
                removed = true;
                break;
            }
        }
        if (!removed) {
            // If no pairs found, remaining length = insertions needed
            moves += s.length;
            break;
        }
    }

